from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a written work into a single fluent sentence.
    """
    if not triples:
        return ""

    # Helper to clean surrounding quotes from object strings
    def clean(o: str) -> str:
        return o.strip().strip('"').strip("'")

    # Mapping from predicate to a clause fragment that follows the subject
    clause_map = {
        "author": "authored by {}",
        "isbnNumber": "ISBN {}",
        "followedBy": "followed by {}",
        "precededBy": "preceded by {}",
        "language": "written in {}",
        "mediaType": "a {} publication",
        "numberOfPages": "contains {} pages",
        "country": "originates from {}",
        "publisher": "published by {}",
        "releaseDate": "released on {}",
        "birthDate": "born on {}",
        "genre": "belongs to the {} genre",
        "literaryGenre": "belongs to the {} genre",
    }

    # Group triples by subject
    subjects = {t.subject for t in triples}
    if len(subjects) == 1:
        # All triples share the same subject – build a compact sentence
        subject = triples[0].subject
        clauses = []
        for t in triples:
            p, o = t.predicate, clean(t.object)
            template = clause_map.get(p, None)
            if template:
                clause = template.format(o)
            else:
                clause = f"{p} {o}"
            clauses.append(clause)

        # Join clauses with commas and a final 'and'
        if len(clauses) == 1:
            sentence = f"{subject} {clauses[0]}."
        else:
            sentence = f"{subject} " + ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
        return sentence
    else:
        # Fallback: treat each triple separately as before
        parts = []
        for t in triples:
            s, p, o = t.subject, t.predicate, clean(t.object)

            if p == "author":
                phrase = f"{s} was authored by {o}"
            elif p == "isbnNumber":
                phrase = f"{s} has ISBN {o}"
            elif p == "followedBy":
                phrase = f"{s} is followed by {o}"
            elif p == "precededBy":
                phrase = f"{s} is preceded by {o}"
            elif p == "language":
                phrase = f"{s} is written in {o}"
            elif p == "mediaType":
                phrase = f"{s} is a {o} publication"
            elif p == "numberOfPages":
                phrase = f"{s} contains {o} pages"
            elif p == "country":
                phrase = f"{s} originates from {o}"
            elif p == "publisher":
                phrase = f"{s} was published by {o}"
            elif p == "releaseDate":
                phrase = f"{s} was released on {o}"
            elif p == "birthDate":
                phrase = f"{s} was born on {o}"
            elif p == "genre" or p == "literaryGenre":
                phrase = f"{s} belongs to the {o} genre"
            else:
                phrase = f"{s} has {p} {o}"
            parts.append(phrase)

        if len(parts) == 1:
            return parts[0] + "."
        else:
            return ", ".join(parts[:-1]) + ", and " + parts[-1] + "."

# EVOLVE-BLOCK-END

